  static List<EventModel> get featured => all.where((e) => e.isFeatured).toList();
  static List<EventModel> getByCategory(String cat) => all.where((e) => e.category == cat).toList();
  static List<EventModel> search(String q) {
    final query = q.toLowerCase();
    return all.where((e) =>
      e.name.toLowerCase().contains(query) ||
      e.artist.toLowerCase().contains(query) ||
      e.category.toLowerCase().contains(query) ||
      e.city.toLowerCase().contains(query)
    ).toList();
  }
